mapper.insert:
insert into t_sync_log (id, targetMethod, tableObject, 
  dataFrom, dataTo, syncParams, 
  syncStartTime, syncEndTime, isSuccess, 
  dataCount, syncType, exception
  )
values (#{id,jdbcType=INTEGER}, #{targetMethod,jdbcType=CHAR}, #{tableObject,jdbcType=CHAR}, 
  #{dataFrom,jdbcType=CHAR}, #{dataTo,jdbcType=CHAR}, #{syncParams,jdbcType=VARCHAR}, 
  #{syncStartTime,jdbcType=TIMESTAMP}, #{syncEndTime,jdbcType=TIMESTAMP}, #{isSuccess,jdbcType=BIT}, 
  #{dataCount,jdbcType=INTEGER}, #{syncType,jdbcType=SMALLINT}, #{exception,jdbcType=LONGVARCHAR}
  )

mapper.select:
    select 
    from t_sync_log
    
        
            
			  and targetMethod = #{model.targetMethod,jdbcType=CHAR}
			
			
			  and tableObject = #{model.tableObject,jdbcType=CHAR}
			
			
			  and dataFrom = #{model.dataFrom,jdbcType=CHAR}
			
			
			  and dataTo = #{model.dataTo,jdbcType=CHAR}
			
			
			  and syncParams = #{model.syncParams,jdbcType=VARCHAR}
			
			
			  and syncStartTime = #{model.syncStartTime,jdbcType=TIMESTAMP}
			
			
			  and syncEndTime = #{model.syncEndTime,jdbcType=TIMESTAMP}
			
			
			  and isSuccess = #{model.isSuccess,jdbcType=BIT}
			
			
			  and dataCount = #{model.dataCount,jdbcType=INTEGER}
			
			
			  and syncType = #{model.syncType,jdbcType=SMALLINT}
			
			
			  and exception = #{model.exception,jdbcType=LONGVARCHAR}
			
			
              and (
                targetMethod like CONCAT("%", #{fuzzy}, "%") or
